#include<bits/stdc++.h>
using namespace std;

#define ll long long

ll n, m, dp[100001], pos = 0, w[1000001], v[1000001];
string a, b;
int main() {
	cin >> a >> b;
	if (a.size()<5|| b.size()< 5) {
		if(a.size()<5)	a = '0' +a;
		if(b.size()<5) b = '0' + b;
	}
	m=(((b[0]-a[0])*10)+(b[1]-a[1]))*60+((b[3]-a[3])*10)+(b[4]-a[4]);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		int v1, w1, s, k = 1;
		cin >> w1 >> v1 >> s;
		if (s == 0) s = m / w1;
		while (k <= s) {
			v[++pos] = v1 * k;
			w[pos] = w1 * k;
			s -= k;
			k *= 2;
		}
		if (s) {
			v[++pos] = v1 * s;
			w[pos] = w1 * s;
		}
	}
	for (int i = 1; i <= pos; i++) {
		for (int j = m; j >= w[i]; j--) {
			dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
		}
	}
	cout << dp[m];
	return 0;
}
